import React from "react";
import { motion } from "framer-motion";
import "./index.css";


export default function App() {
  return (
    <div className="bg-gradient-to-br from-black via-gray-900 to-black text-white min-h-screen overflow-x-hidden">
      <Navbar />
      <Hero />
      <Experience />
      <Projects />
      <Contact />
    </div>
  );
}




function Hero() {
  return (
    <div className="text-center py-40 px-6">

      <motion.h1
        initial={{ opacity: 0, y: 40 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.8 }}
        className="text-6xl md:text-7xl font-bold tracking-wide"
      >
        Muhammad Kashif
      </motion.h1>

      <motion.p
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.5 }}
        className="mt-6 text-gray-400 text-xl"
      >
        Full Stack Engineer | Real-Time Systems Specialist
      </motion.p>

      <motion.div
        initial={{ opacity: 0, y: 30 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.8 }}
        className="mt-10 bg-white/5 p-8 rounded-2xl backdrop-blur-xl border border-white/10 max-w-2xl mx-auto shadow-xl"
      >
        <p className="text-gray-300 leading-relaxed">
          Results-driven Software Engineer with 3+ years of experience building scalable,
          high-performance real-time applications using React, Node.js, and WebSockets.
        </p>
      </motion.div>


        {/* <button className="px-6 py-2 bg-blue-600 rounded-lg hover:bg-blue-500 transition">
          View Projects
        </button>
        <button className="px-6 py-2 border border-white/20 rounded-lg hover:bg-white/10 transition">
          Contact Me
        </button> */}

   <div className="mt-10 flex justify-center gap-4">
      <a href="#projects">
        <button className="px-6 py-2 bg-blue-600 rounded-lg hover:bg-blue-500 transition">
          View Projects
        </button>
      </a>

      <a href="#contact">
        <button className="px-6 py-2 border border-white/20 rounded-lg hover:bg-white/10 transition">
          Contact Me
        </button>
      </a>
       </div>

    </div>
  );
}

function Experience() {
  return (
    <div id="exp" className="px-10 py-24 bg-black/70">
      <h2 className="text-4xl font-bold mb-16 text-center">Experience</h2>

      <div className="max-w-6xl mx-auto grid md:grid-cols-2 gap-8">
        {/* Card 1 */}
        <motion.div
          initial={{ opacity: 0, y: 50 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.8 }}
          className="group bg-gradient-to-br from-blue-800/40 via-black/40 to-blue-900/40 p-8 rounded-3xl backdrop-blur-xl border border-white/10 shadow-xl hover:scale-105 transition-transform"
        >
          <div className="flex items-center mb-4">
            <div className="bg-blue-600 p-3 rounded-full mr-4">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 7l6 6-6 6M21 7l-6 6 6 6" />
              </svg>
            </div>
            <h3 className="text-2xl font-semibold text-white">Real-Time Air Traffic & Sensor Systems</h3>
          </div>
          <p className="text-gray-300 mb-4 leading-relaxed">
            Led integration of multiple <strong>sensors</strong> into a large-scale system. Coordinated with vendors and cross-functional teams to ensure seamless data flow.
          </p>
          <div className="flex flex-col gap-2 text-gray-200">
            <div><span className="font-semibold text-blue-400">Technologies:</span> React, React-Leaflet, WebSockets, TCP, UDP</div>
            <div><span className="font-semibold text-blue-400">Achievements:</span> Real-time air traffic monitoring, dynamic map markers, 24/7 uptime</div>
            <div><span className="font-semibold text-blue-400">Responsibilities:</span> Sensor integration, network diagnostics, system optimization</div>
          </div>
        </motion.div>

        {/* Card 2 */}
        <motion.div
          initial={{ opacity: 0, y: 50 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.8, delay: 0.2 }}
          className="group bg-gradient-to-br from-purple-800/40 via-black/40 to-purple-900/40 p-8 rounded-3xl backdrop-blur-xl border border-white/10 shadow-xl hover:scale-105 transition-transform"
        >
          <div className="flex items-center mb-4">
            <div className="bg-purple-600 p-3 rounded-full mr-4">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
              </svg>
            </div>
            <h3 className="text-2xl font-semibold text-white">Full Stack Web Applications</h3>
          </div>
          <p className="text-gray-300 mb-4 leading-relaxed">
            Developed scalable applications for web using <strong>React, Node.js, and Express</strong>. Built interactive map tools with polygon and route creation features.
          </p>
          <div className="flex flex-col gap-2 text-gray-200">
            <div><span className="font-semibold text-purple-400">Technologies:</span> React, Node.js, Express, MongoDB</div>
            <div><span className="font-semibold text-purple-400">Achievements:</span> Interactive map drawing tools, database integration, responsive design</div>
            <div><span className="font-semibold text-purple-400">Responsibilities:</span> Agile development, full stack implementation, performance optimization</div>
          </div>
        </motion.div>
      </div>
    </div>
  );
}

function TimelineItem({ title, date, desc, side }) {
  const isLeft = side === "left";

  return (
    <div className={`mb-16 w-full md:w-1/2 ${isLeft ? "md:pr-8 md:ml-auto text-right" : "md:pl-8 md:mr-auto text-left"}`}>
      <motion.div
        initial={{ opacity: 0, x: isLeft ? -50 : 50 }}
        whileInView={{ opacity: 1, x: 0 }}
        viewport={{ once: true }}
        transition={{ duration: 0.8 }}
        className="relative bg-white/5 p-6 rounded-2xl backdrop-blur-xl border border-white/10 shadow-lg"
      >
        <span className="absolute -top-5 w-5 h-5 bg-blue-600 rounded-full left-1/2 transform -translate-x-1/2 border border-white/10"></span>
        <h3 className="text-2xl font-semibold">{title}</h3>
        <p className="text-sm text-blue-400 mt-1">{date}</p>
        <p className="mt-4 text-gray-300 leading-relaxed">{desc}</p>
      </motion.div>
    </div>
  );
}

function Projects() {
  return (
    <div id="projects" className="px-10 py-24 bg-black/70">
      <h2 className="text-4xl font-bold mb-16 text-center">Projects</h2>

      <div className="max-w-6xl mx-auto grid md:grid-cols-3 gap-8">

        {/* Project 1 */}
        <motion.div
          initial={{ opacity: 0, y: 50 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.8 }}
          className="group bg-gradient-to-br from-blue-800/40 via-black/40 to-blue-900/40 p-8 rounded-3xl backdrop-blur-xl border border-white/10 shadow-xl hover:scale-105 transition-transform"
        >
          <div className="flex items-center mb-4">
            <div className="bg-blue-600 p-3 rounded-full mr-4">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 7l6 6-6 6M21 7l-6 6 6 6" />
              </svg>
            </div>
            <h3 className="text-2xl font-semibold text-white">Air Traffic Application</h3>
          </div>
          <p className="text-gray-300 mb-4 leading-relaxed">
            High-availability <strong>React-Leaflet</strong> app for real-time air traffic monitoring. Dynamic map markers, layers, and popups display aircraft, sensor locations, and maintenance alerts.
          </p>
          <div className="flex flex-col gap-2 text-gray-200">
            <div><span className="font-semibold text-blue-400">Technologies:</span> React, React-Leaflet, WebSockets, TCP, UDP</div>
            <div><span className="font-semibold text-blue-400">Features:</span> Live updates, dynamic markers, 24/7 uptime, low-latency visualization</div>
          </div>
        </motion.div>

        {/* Project 2 */}
        <motion.div
          initial={{ opacity: 0, y: 50 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.8, delay: 0.2 }}
          className="group bg-gradient-to-br from-purple-800/40 via-black/40 to-purple-900/40 p-8 rounded-3xl backdrop-blur-xl border border-white/10 shadow-xl hover:scale-105 transition-transform"
        >
          <div className="flex items-center mb-4">
            <div className="bg-purple-600 p-3 rounded-full mr-4">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
              </svg>
            </div>
            <h3 className="text-2xl font-semibold text-white">Map Drawing Tools</h3>
          </div>
          <p className="text-gray-300 mb-4 leading-relaxed">
            Interactive map tools for creating <strong>polygons, lines, and markers</strong>. Captures coordinates in real-time with database integration. Supports saving, editing, and reloading user-generated shapes.
          </p>
          <div className="flex flex-col gap-2 text-gray-200">
            <div><span className="font-semibold text-purple-400">Technologies:</span> React, Leaflet, MongoDB, Node.js</div>
            <div><span className="font-semibold text-purple-400">Features:</span> Polygon drawing, real-time coordinates, tooltips, markers, and layer management</div>
          </div>
        </motion.div>

        {/* Project 3 */}
        <motion.div
          initial={{ opacity: 0, y: 50 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.8, delay: 0.4 }}
          className="group bg-gradient-to-br from-green-800/40 via-black/40 to-green-900/40 p-8 rounded-3xl backdrop-blur-xl border border-white/10 shadow-xl hover:scale-105 transition-transform"
        >
          <div className="flex items-center mb-4">
            <div className="bg-green-600 p-3 rounded-full mr-4">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
              </svg>
            </div>
            <h3 className="text-2xl font-semibold text-white">Sensor Integration</h3>
          </div>
          <p className="text-gray-300 mb-4 leading-relaxed">
            Integrated multiple <strong>sensors</strong> with web applications, ensuring seamless data flow and real-time visualization. Coordinated with third-party vendors and optimized system performance for 24/7 operation.
          </p>
          <div className="flex flex-col gap-2 text-gray-200">
            <div><span className="font-semibold text-green-400">Technologies:</span> React, WebSockets, TCP, UDP, Node.js</div>
            <div><span className="font-semibold text-green-400">Features:</span> Real-time sensor data, live visualization, low-latency updates, 24/7 high availability</div>
          </div>
        </motion.div>

      </div>
    </div>
  );
}

function Card({ title, desc }) {
  return (
    <div className="bg-white/5 p-8 rounded-2xl backdrop-blur-xl border border-white/10 hover:scale-105 hover:border-blue-500 transition shadow-lg">
      <h3 className="text-2xl font-semibold">{title}</h3>
      <p className="mt-3 text-gray-400">{desc}</p>
    </div>
  );
}

// function Card({ title, desc }) {
//   return (
//     <div className="bg-white/5 p-8 rounded-2xl backdrop-blur-xl border border-white/10 hover:scale-105 hover:border-blue-500 transition shadow-lg">
//       <h3 className="text-2xl font-semibold">{title}</h3>
//       <p className="mt-3 text-gray-400">{desc}</p>
//     </div>
//   );
// }

function Contact() {
  return (
    <div id="contact" className="px-10 py-24">
      <h2 className="text-4xl font-bold mb-12 text-center">Contact</h2>

      <form className="space-y-5 max-w-xl mx-auto bg-white/5 p-10 rounded-2xl backdrop-blur-xl border border-white/10 shadow-lg">
        <input placeholder="Name" className="w-full p-3 rounded bg-black/40 outline-none" />
        <input placeholder="Email" className="w-full p-3 rounded bg-black/40 outline-none" />
        <textarea placeholder="Message" className="w-full p-3 rounded bg-black/40 outline-none" />

        <button className="w-full bg-blue-600 py-3 rounded-lg hover:bg-blue-500 transition">
          Send Message
        </button>
      </form>
    </div>
  );
}
